# API/REST Best Practices

## FastAPI (Python)

### Basic Structure
```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class User(BaseModel):
    name: str
    email: str

@app.post("/users", status_code=201)
async def create_user(user: User):
    # Validation happens automatically via Pydantic
    return {"id": 1, **user.dict()}

@app.get("/users/{user_id}")
async def get_user(user_id: int):
    user = db.get_user(user_id)
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    return user
```

### Dependency Injection
```python
from fastapi import Depends

def get_db():
    db = Database()
    try:
        yield db
    finally:
        db.close()

@app.get("/items")
async def list_items(db: Database = Depends(get_db)):
    return db.query(Item).all()
```

### Error Handling
```python
@app.exception_handler(ValueError)
async def value_error_handler(request, exc):
    return JSONResponse(
        status_code=400,
        content={"error": str(exc)}
    )
```

## Express (Node.js)

### Basic Structure
```typescript
import express from 'express';

const app = express();
app.use(express.json());

interface User {
  name: string;
  email: string;
}

app.post('/users', (req, res) => {
  const user: User = req.body;

  if (!user.name || !user.email) {
    return res.status(400).json({ error: 'Missing fields' });
  }

  res.status(201).json({ id: 1, ...user });
});

app.get('/users/:id', (req, res) => {
  const user = db.getUser(req.params.id);

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  res.json(user);
});
```

### Middleware
```typescript
// Request validation middleware
const requireWorkspace = (req, res, next) => {
  const workspaceId = req.headers['x-workspace-id'];

  if (!workspaceId) {
    return res.status(400).json({ error: 'Missing workspace id' });
  }

  req.workspaceId = workspaceId;
  next();
};

app.get('/workspace', requireWorkspace, (req, res) => {
  res.json({ workspaceId: req.workspaceId });
});
```

## REST Conventions

### HTTP Methods
```
GET    /users      → List all users
GET    /users/:id  → Get specific user
POST   /users      → Create user
PUT    /users/:id  → Replace user (full update)
PATCH  /users/:id  → Update user (partial)
DELETE /users/:id  → Delete user
```

### Status Codes
```
200 OK           → Successful GET/PUT/PATCH
201 Created      → Successful POST
204 No Content   → Successful DELETE
400 Bad Request  → Validation error
401 Unauthorized → Missing/invalid auth
403 Forbidden    → Auth OK, but not allowed
404 Not Found    → Resource doesn't exist
500 Server Error → Internal error
```

### Response Structure
```json
// ✅ Good: Consistent structure
{
  "data": { "id": 1, "name": "John" },
  "error": null
}

// Error response
{
  "data": null,
  "error": {
    "code": "VALIDATION_ERROR",
    "message": "Email is required",
    "fields": ["email"]
  }
}
```

## Common Patterns

### Pagination
```python
@app.get("/items")
async def list_items(page: int = 1, per_page: int = 20):
    offset = (page - 1) * per_page
    items = db.query(Item).offset(offset).limit(per_page).all()
    total = db.query(Item).count()

    return {
        "items": items,
        "page": page,
        "per_page": per_page,
        "total": total,
        "pages": (total + per_page - 1) // per_page
    }
```

### Filtering/Sorting
```python
@app.get("/items")
async def list_items(
    status: Optional[str] = None,
    sort_by: str = "created_at",
    order: str = "desc"
):
    query = db.query(Item)

    if status:
        query = query.filter(Item.status == status)

    if order == "desc":
        query = query.order_by(Item[sort_by].desc())
    else:
        query = query.order_by(Item[sort_by].asc())

    return query.all()
```

# Testing Best Practices

## Python (pytest)

### Basic Structure
```python
# test_calculator.py
import pytest

def test_add():
    assert add(2, 3) == 5

def test_divide_by_zero():
    with pytest.raises(ZeroDivisionError):
        divide(1, 0)
```

### Fixtures
```python
@pytest.fixture
def db_session():
    session = create_session()
    yield session
    session.close()

def test_user_creation(db_session):
    user = User(name="John")
    db_session.add(user)
    assert user.id is not None
```

### Parametrize
```python
@pytest.mark.parametrize("input,expected", [
    (2, 4),
    (3, 9),
    (4, 16),
])
def test_square(input, expected):
    assert square(input) == expected
```

### Mocking
```python
from unittest.mock import Mock, patch

def test_api_call():
    with patch('requests.get') as mock_get:
        mock_get.return_value.json.return_value = {'data': 'test'}
        result = fetch_data('url')
        assert result == {'data': 'test'}
```

## JavaScript/TypeScript (Jest/Vitest)

### Basic Structure
```typescript
// calculator.test.ts
import { describe, it, expect } from 'vitest';

describe('Calculator', () => {
  it('adds two numbers', () => {
    expect(add(2, 3)).toBe(5);
  });

  it('throws on divide by zero', () => {
    expect(() => divide(1, 0)).toThrow();
  });
});
```

### React Testing
```typescript
import { render, screen, fireEvent } from '@testing-library/react';

test('button click updates count', () => {
  render(<Counter />);
  const button = screen.getByRole('button');

  fireEvent.click(button);

  expect(screen.getByText('Count: 1')).toBeInTheDocument();
});
```

### Mocking
```typescript
import { vi } from 'vitest';

test('calls API', async () => {
  const mockFetch = vi.fn().mockResolvedValue({ data: 'test' });
  global.fetch = mockFetch;

  await fetchData('url');

  expect(mockFetch).toHaveBeenCalledWith('url');
});
```

## Best Practices

### AAA Pattern
```python
def test_user_login():
    # Arrange
    user = User(email="test@example.com")

    # Act
    result = login(user)

    # Assert
    assert result.success is True
```

### Test Naming
```python
# ✅ Good: Descriptive
def test_user_cannot_login_with_invalid_password():
    ...

# ❌ Bad: Vague
def test_login():
    ...
```

### One Assertion Focus
```python
# ✅ Good: Tests one thing
def test_user_email_is_lowercase():
    user = User(email="TEST@Example.com")
    assert user.email == "test@example.com"

# ❌ Bad: Tests multiple things
def test_user():
    user = User(email="TEST@Example.com")
    assert user.email == "test@example.com"
    assert user.is_active is True
    assert len(user.tokens) == 1
```

### Test Independence
```python
# ✅ Good: Independent tests
def test_create_user():
    user = create_user()
    assert user.id is not None

def test_delete_user():
    user = create_user()  # Own setup
    delete_user(user.id)
    assert get_user(user.id) is None
```
